using Dapper;using Flak.Infrastructure.Database;using Flak.Infrastructure.Models;namespace Flak.Infrastructure.Repositories; public sealed class UserAccountRepository { private readonly DbConnectionFactory _f; public UserAccountRepository(DbConnectionFactory f)=>_f=f; public async Task<IEnumerable<UserAccount>> GetAllAsync(CancellationToken ct){const string sql="select id, username, email, is_active as IsActive from user_accounts order by username;"; await using var c=await _f.OpenConnectionAsync(ct); return await c.QueryAsync<UserAccount>(new CommandDefinition(sql,cancellationToken:ct));} public async Task<UserAccount?> GetByIdAsync(Guid id,CancellationToken ct){const string sql="select id, username, email, password_hash as PasswordHash, is_active as IsActive from user_accounts where id=@Id limit 1;"; await using var c=await _f.OpenConnectionAsync(ct); return await c.QuerySingleOrDefaultAsync<UserAccount>(new CommandDefinition(sql,new{Id=id},cancellationToken:ct));} public async Task<UserAccount?> GetByUsernameAsync(string username,CancellationToken ct){const string sql="select id, username, email, password_hash as PasswordHash, is_active as IsActive from user_accounts where username=@Username limit 1;"; await using var c=await _f.OpenConnectionAsync(ct); return await c.QuerySingleOrDefaultAsync<UserAccount>(new CommandDefinition(sql,new{Username=username},cancellationToken:ct));} public async Task<UserAccount?> GetByEmailAsync(string email,CancellationToken ct){const string sql="select id, username, email, password_hash as PasswordHash, is_active as IsActive from user_accounts where email=@Email limit 1;"; await using var c=await _f.OpenConnectionAsync(ct); return await c.QuerySingleOrDefaultAsync<UserAccount>(new CommandDefinition(sql,new{Email=email},cancellationToken:ct));} public async Task<Guid> CreateAsync(string username,string email,string passwordHash,CancellationToken ct){const string sql="insert into user_accounts (id,username,email,password_hash,is_active,created_utc,updated_utc) values (gen_random_uuid(),@Username,@Email,@PasswordHash,true,now(),now()) returning id;"; await using var c=await _f.OpenConnectionAsync(ct); return await c.ExecuteScalarAsync<Guid>(new CommandDefinition(sql,new{Username=username,Email=email,PasswordHash=passwordHash},cancellationToken:ct));} public async Task<bool> HasActivePlatformAdminAsync(CancellationToken ct){const string sql="select exists (select 1 from user_accounts u join user_roles ur on ur.user_id=u.id join roles r on r.id=ur.role_id where u.is_active=true and r.name='PlatformAdmin');"; await using var c=await _f.OpenConnectionAsync(ct); return await c.ExecuteScalarAsync<bool>(new CommandDefinition(sql,cancellationToken:ct));} }